const LAKES={
  'Taylorsville Lake':{name:'Taylorsville Lake',short:'Taylorsville',center:[38.00665,-85.26772],zoom:15},
  'Nolin Lake':{name:'Nolin Lake',short:'Nolin',center:[37.30040,-86.22690],zoom:13},
  'Rough River Lake':{name:'Rough River Lake',short:'Rough River',center:[37.61160,-86.50780],zoom:13},
  'Green River Lake':{name:'Green River Lake',short:'Green River',center:[37.24970,-85.34440],zoom:13}
};
const SELECTED_LAKE_STORE='fishlog_v1_selected_lake';
let selectedLakeName=localStorage.getItem(SELECTED_LAKE_STORE)||'Taylorsville Lake';
if(!LAKES[selectedLakeName])selectedLakeName='Taylorsville Lake';
let LAKE_CENTER=[...LAKES[selectedLakeName].center];
const STORE='fishlog_v1_catches';
const LURE_STORE='fishlog_v1_lures';
const DEFAULT_BASS_IMG=`data:image/webp;base64,`;
const LURE_DB={
  'Soft Plastics':[
    {name:'Rage Craw',colors:['Green Pumpkin','Black Blue Flake','Watermelon Red','Bama Craw']},
    {name:'Senko / Stick Worm',colors:['Green Pumpkin','Black Blue','Watermelon Candy','Junebug']},
    {name:'Brush Hog',colors:['Green Pumpkin','Watermelon Red','Black Sapphire']},
    {name:'Bronco Bug',colors:['Green Pumpkin','Black Blue','Okeechobee Craw']},
    {name:'D Bomb',colors:['Super Bug','Green Pumpkin','Black Blue']},
    {name:'Other Soft Plastic',colors:['Custom / Other']}
  ],
  'Jigs':[
    {name:'Flipping Jig',colors:['PB&J','Black Blue','Green Pumpkin','Craw']},
    {name:'Football Jig',colors:['Green Pumpkin','Brown Orange','PB&J']},
    {name:'Swim Jig',colors:['Bluegill','White','Green Pumpkin']},
    {name:'Other Jig',colors:['Custom / Other']}
  ],
  'Crankbaits':[
    {name:'Bandit 100',colors:['Chartreuse Black Back','Crawfish','Shad']},
    {name:'Bandit 200',colors:['Chartreuse Black Back','Rootbeer','Pearl Shad']},
    {name:'Rapala DT',colors:['Demon','Bluegill','Shad']},
    {name:'Squarebill',colors:['Sexy Shad','Chartreuse Black Back','Craw']},
    {name:'Other Crankbait',colors:['Custom / Other']}
  ],
  'Spinnerbaits / Chatterbaits':[
    {name:'ChatterBait',colors:['Green Pumpkin','Black Blue','White Chartreuse']},
    {name:'Spinnerbait',colors:['White','Chartreuse White','Bluegill']},
    {name:'Thunder Cricket',colors:['Green Pumpkin','Black Blue','White']},
    {name:'Other Bladed Bait',colors:['Custom / Other']}
  ],
  'Topwater':[
    {name:'Whopper Plopper',colors:['Bone','Loon','Bluegill']},
    {name:'Popper',colors:['Bone','Shad','Bluegill']},
    {name:'Walking Bait',colors:['Chrome','Bone','Sexy Shad']},
    {name:'Frog',colors:['Black','White','Leopard']},
    {name:'Other Topwater',colors:['Custom / Other']}
  ],
  'Other':[
    {name:'Custom / Other',colors:['Custom / Other']}
  ]
};
let map, markersLayer, zoneLayer, manualLayer, currentLatLng=[...LAKE_CENTER];
let editMode=false;
let currentPhotoData='';
let selectedLure='Rage Craw - Green Pumpkin';
let catches=load(STORE, seedCatches());
let lures=load(LURE_STORE,['Soft Plastics | Rage Craw - Green Pumpkin','Crankbaits | Bandit 200 - Chartreuse Black Back','Jigs | Flipping Jig - PB&J','Soft Plastics | Bronco Bug - Green Pumpkin']);
let currentWeather=null;
let weatherCoords=[...LAKE_CENTER];
let weatherLabel=selectedLakeName;
let lastPatternCluster=null;

function load(k,fallback){try{return JSON.parse(localStorage.getItem(k))??fallback}catch{return fallback}}
function save(){localStorage.setItem(STORE,JSON.stringify(catches));localStorage.setItem(LURE_STORE,JSON.stringify(lures));}
function selectedLake(){return LAKES[selectedLakeName]||LAKES['Taylorsville Lake'];}
function lakeForCatch(c){return c.lake||'Taylorsville Lake';}
function activeCatches(){return catches.filter(c=>lakeForCatch(c)===selectedLakeName);}
function updateLakeButton(){const btn=document.querySelector('.lakeBtn'); if(btn)btn.textContent=`${selectedLake().short} Lake ▾`;}
function closeLakeMenu(){document.getElementById('lakeMenu')?.remove();}
function toggleLakeMenu(){
  let menu=document.getElementById('lakeMenu');
  if(menu){menu.remove();return;}
  menu=document.createElement('div');
  menu.id='lakeMenu';
  menu.className='lakeMenu';
  menu.innerHTML=Object.keys(LAKES).map(name=>`<button type="button" data-lake="${escapeHtml(name)}" class="${name===selectedLakeName?'active':''}">${escapeHtml(name)}</button>`).join('');
  document.body.appendChild(menu);
  const btn=document.querySelector('.lakeBtn');
  if(btn){
    const r=btn.getBoundingClientRect();
    menu.style.top=`${Math.round(r.bottom+8)}px`;
    menu.style.left=`${Math.round(Math.max(12,Math.min(window.innerWidth-230,r.left-26)))}px`;
  }
  menu.querySelectorAll('button').forEach(b=>b.onclick=()=>setSelectedLake(b.dataset.lake,true));
}
function setSelectedLake(name,fly=true){
  if(!LAKES[name])return;
  selectedLakeName=name;
  localStorage.setItem(SELECTED_LAKE_STORE,name);
  LAKE_CENTER=[...LAKES[name].center];
  currentLatLng=[...LAKE_CENTER];
  weatherCoords=[...LAKE_CENTER];
  weatherLabel=name;
  updateLakeButton();
  updateLocationField();
  closeLakeMenu();
  if(manualLayer)manualLayer.clearLayers();
  fetchWeather(LAKE_CENTER[0],LAKE_CENTER[1],name);
  renderMap();
  renderPattern();
  if(document.getElementById('historyView')?.classList.contains('active'))renderHistory();
  if(document.getElementById('statsView')?.classList.contains('active'))renderStats();
  if(map&&fly)map.flyTo(LAKE_CENTER,selectedLake().zoom||13,{animate:true,duration:.8});
  flashMessage(`Switched to ${name}. New catches will save to this lake.`);
}

function seedCatches(){return[{id:crypto.randomUUID(),species:'Largemouth Bass',length:18.5,weight:3.2,lure:'Rage Craw - Green Pumpkin',depth:8,waterTemp:68,keeper:true,keeperRule:'auto',areaType:'First 1/4 of cove',coverType:'Wood / laydown',weather:null,lake:'Taylorsville Lake',lat:38.00665,lng:-85.26772,notes:'Sample catch. Tap pin for details. New catches can include a fish photo.',photo:'',date:new Date().toISOString()}]}

function initMap(){
  map=L.map('map',{zoomControl:false,tap:true}).setView(LAKE_CENTER,selectedLake().zoom||15);
  L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',{maxZoom:19,attribution:'Tiles © Esri'}).addTo(map);
  markersLayer=L.layerGroup().addTo(map); zoneLayer=L.layerGroup().addTo(map); manualLayer=L.layerGroup().addTo(map);
  map.on('click',e=>{setManualLocation(e.latlng.lat,e.latlng.lng,true);});
  map.on('zoomend moveend',()=>renderMap());
  renderMap();
  setTimeout(()=>map.invalidateSize(),300);
}

function getTrophyCatch(pool=catches){
  if(!pool.length)return null;
  return pool.slice().sort((a,b)=>{
    const len=(+b.length||0)-(+a.length||0);
    if(len)return len;
    const wt=(+b.weight||0)-(+a.weight||0);
    if(wt)return wt;
    return new Date(b.date||0)-new Date(a.date||0);
  })[0];
}
function markerIcon(c,isTrophy=false){return L.divIcon({className:'',html:`<div class="fishMarker ${isTrophy?'trophyPulse':''}"><span>${isTrophy?'🏆':'🐟'}</span></div>`,iconSize:[42,42],iconAnchor:[21,42]});}
function clusterIcon(n,hasTrophy=false){return L.divIcon({className:'',html:`<div class="clusterMarker ${hasTrophy?'trophyCluster':''}"><span>${n}</span></div>`,iconSize:[58,58],iconAnchor:[29,29]});}
function renderMap(){
  if(!markersLayer)return;
  markersLayer.clearLayers();
  zoneLayer.clearLayers();
  const zoom=map.getZoom();
  const visibleCatches=activeCatches();
  const trophy=getTrophyCatch(visibleCatches);
  const clusterRadius=clusterRadiusForZoom(zoom);
  const groups=clusterCatches(visibleCatches,clusterRadius);
  groups.forEach(g=>{
    const hasTrophy=!!trophy && g.items.some(c=>c.id===trophy.id);
    if(g.items.length>1 && shouldClusterGroup(g,zoom)){
      const m=L.marker(g.center,{icon:clusterIcon(g.items.length,hasTrophy)}).addTo(markersLayer);
      const zoomIn=e=>{if(e)L.DomEvent.stopPropagation(e); zoomToCatchCluster(g);};
      m.on('click',zoomIn);
      m.on('touchstart',zoomIn);
    } else {
      g.items.forEach((c,idx)=>{
        const isTrophy=!!trophy && c.id===trophy.id;
        const pinLatLng=offsetClusteredPin([c.lat,c.lng],idx,g.items.length,zoom);
        const m=L.marker(pinLatLng,{icon:markerIcon(c,isTrophy)}).addTo(markersLayer);
        m.bindPopup(`<b>${isTrophy?'🏆 ':''}${escapeHtml(c.species)}</b><br>${fmt(c.length)} in · ${fmt(c.weight)} lb<br>${escapeHtml(c.lure||'No lure')}`);
        const open=e=>{if(e)L.DomEvent.stopPropagation(e); showCatchDetail(c.id);};
        m.on('click',open);
        m.on('touchstart',open);
      });
    }
  });
  renderBigFishZones(groups);
}
function clusterRadiusForZoom(zoom){
  if(zoom<13)return 180;
  if(zoom<15)return 120;
  if(zoom<17)return 80;
  if(zoom<18)return 45;
  return 18;
}
function shouldClusterGroup(g,zoom){
  return g.items.length>1 && zoom<18;
}
function zoomToCatchCluster(g){
  const bounds=L.latLngBounds(g.items.map(c=>[c.lat,c.lng]));
  if(bounds.isValid() && !bounds.getNorthEast().equals(bounds.getSouthWest())){
    map.fitBounds(bounds.pad(.35),{maxZoom:18,animate:true});
  } else {
    map.setView(g.center,18,{animate:true});
  }
  setTimeout(renderMap,350);
}
function offsetClusteredPin(latLng,index,total,zoom){
  if(total<=1 || zoom<18 || !map)return latLng;
  const radius=Math.min(42,20+(total*3));
  const angle=(Math.PI*2*index)/total;
  const p=map.latLngToLayerPoint(latLng);
  const offset=L.point(p.x+Math.cos(angle)*radius,p.y+Math.sin(angle)*radius);
  const ll=map.layerPointToLatLng(offset);
  return [ll.lat,ll.lng];
}
function renderBigFishZones(groups){
  groups.forEach(g=>{
    const q=g.items.filter(c=>/bass/i.test(c.species||'') && (+c.length>=15));
    if(q.length>=3){
      const avg=q.reduce((s,c)=>s+(+c.length||0),0)/q.length;
      const circle=L.circle(g.center,{radius:70,color:'#f2b23b',fillColor:'#f2b23b',fillOpacity:Math.min(.35,.13+q.length*.03),weight:2}).addTo(zoneLayer);
      circle.on('click touchstart',()=>showZoneDetail(q,avg));
    }
  });
}
function clusterCatches(items,radiusMeters){
  const groups=[];
  for(const c of items){
    let placed=false;
    for(const g of groups){
      if(distanceMeters([c.lat,c.lng],g.center)<radiusMeters){g.items.push(c);g.center=[g.items.reduce((s,x)=>s+x.lat,0)/g.items.length,g.items.reduce((s,x)=>s+x.lng,0)/g.items.length];placed=true;break;}
    }
    if(!placed)groups.push({center:[c.lat,c.lng],items:[c]});
  }
  return groups;
}
function distanceMeters(a,b){const R=6371000,rad=x=>x*Math.PI/180;const dLat=rad(b[0]-a[0]),dLng=rad(b[1]-a[1]);const s=Math.sin(dLat/2)**2+Math.cos(rad(a[0]))*Math.cos(rad(b[0]))*Math.sin(dLng/2)**2;return 2*R*Math.asin(Math.sqrt(s));}

const SMALLMOUTH_IMG=`data:image/jpeg;base64,`;
const SPOTTED_BASS_IMG=`data:image/jpeg;base64,`;
const CRAPPIE_IMG=`data:image/jpeg;base64,`;
const CATFISH_IMG=`data:image/jpeg;base64,`;
const BLUEGILL_IMG=`data:image/jpeg;base64,`;
const GENERIC_FISH_IMG=`data:image/jpeg;base64,`;
const SPECIES_IMAGES={
  'largemouth bass':DEFAULT_BASS_IMG,
  'smallmouth bass':SMALLMOUTH_IMG,
  'spotted bass':SPOTTED_BASS_IMG,
  'crappie':CRAPPIE_IMG,
  'catfish':CATFISH_IMG,
  'bluegill':BLUEGILL_IMG,
  'other':GENERIC_FISH_IMG
};
function speciesKey(species=''){const s=String(species||'').trim().toLowerCase(); return SPECIES_IMAGES[s]?s:'other';}
function speciesThumbLabel(species=''){const key=speciesKey(species); return key==='other'?'Fish image':`${String(species||'Fish')} image`;}
function speciesImage(c){return SPECIES_IMAGES[speciesKey(c?.species)] || GENERIC_FISH_IMG;}
function catchPhoto(c){return c.photo || '';}
function photoThumb(src,label,extraClass='',clickable=true){if(!src)return ''; const safeLabel=escapeHtml(label); return clickable?`<button type="button" class="photoThumbBtn ${extraClass}" data-photo="${src}" aria-label="Open ${safeLabel}"><img src="${src}" alt="${safeLabel}"><span>${safeLabel}</span></button>`:`<div class="photoThumbBtn ${extraClass}" aria-label="${safeLabel}"><img src="${src}" alt="${safeLabel}"><span>${safeLabel}</span></div>`;}
function attachPhotoThumbs(root=document){root.querySelectorAll('[data-photo]').forEach(el=>{el.onclick=e=>{e.stopPropagation(); openPhotoModal(el.dataset.photo);};});}
function showCatchDetail(id){const c=catches.find(x=>x.id===id); if(!c)return; const speciesThumb=speciesImage(c); const speciesLabel=speciesThumbLabel(c.species); const uploadThumb=catchPhoto(c); const photoHelp=uploadThumb?`${speciesLabel} is display only. Catch photo opens full size.`:`${speciesLabel} is display only.`; const hero=(speciesThumb||uploadThumb)?`<div class="fishHero"><div class="fishHeroTitle"><h2 class="detailTitle">${escapeHtml(c.species)} ${keeperBadge(c)}</h2><p>${escapeHtml(photoHelp)}</p></div><div class="fishThumbRail">${photoThumb(speciesThumb,speciesLabel,'speciesPhotoThumb',false)}${photoThumb(uploadThumb,'Catch photo','userPhotoThumb',true)}</div></div>`:`<h2 class="detailTitle">${escapeHtml(c.species)} ${keeperBadge(c)}</h2>`; const sheet=document.getElementById('sheetContent'); sheet.innerHTML=`${hero}<div class="detailGrid"><div><b>${fmt(c.length)} in</b><small>Length</small></div><div><b>${fmt(c.weight)} lb</b><small>Weight</small></div><div><b>${escapeHtml(c.lure||'—')}</b><small>Lure</small></div><div><b>${fmt(c.depth)} ft</b><small>Depth</small></div><div><b>${fmt(c.waterTemp)}°F</b><small>Water temp</small></div><div><b>${new Date(c.date).toLocaleDateString()}</b><small>Date</small></div><div><b>${escapeHtml(lakeForCatch(c))}</b><small>Lake</small></div><div><b>${escapeHtml(c.areaType||'Not logged')}</b><small>Area type</small></div><div><b>${escapeHtml(c.coverType||'Not logged')}</b><small>Cover type</small></div><div class="detailWide"><b>${escapeHtml(weatherSummary(c.weather))}</b><small>Saved weather</small></div></div><p>${escapeHtml(c.notes||'')}</p><p class="muted">${c.lat.toFixed(5)}, ${c.lng.toFixed(5)}</p>`; attachPhotoThumbs(sheet); openSheet();}
function showZoneDetail(q,avg){const big=q.reduce((a,b)=>(+b.length||0)>(+a.length||0)?b:a,q[0]); document.getElementById('sheetContent').innerHTML=`<h2 class="detailTitle">Big Fish Zone</h2><p>${q.length} qualifying bass 15 inches or larger.</p><div class="detailGrid"><div><b>${avg.toFixed(1)} in</b><small>Average length</small></div><div><b>${big.length} in</b><small>Largest bass</small></div><div><b>${escapeHtml(bestLure(q))}</b><small>Best lure</small></div><div><b>${q.length}</b><small>Qualifying catches</small></div></div>`; openSheet();}
function bestLure(arr){const m={};arr.forEach(c=>m[c.lure]=(m[c.lure]||0)+1);return Object.entries(m).sort((a,b)=>b[1]-a[1])[0]?.[0]||'—'}
function openSheet(){document.getElementById('detailSheet').classList.remove('hidden')}function closeSheet(){document.getElementById('detailSheet').classList.add('hidden')}

function switchView(id){document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(id).classList.add('active');document.querySelectorAll('.bottomNav button').forEach(b=>b.classList.toggle('active',b.dataset.view===id)); if(id==='mapView')setTimeout(()=>{map.invalidateSize();renderMap();},150); if(id==='patternView')renderPattern(); if(id==='historyView')renderHistory(); if(id==='statsView')renderStats(); if(id==='luresView')renderLures();}
function updateLocationField(){const el=document.getElementById('locationText'); if(el) el.value=`${currentLatLng[0].toFixed(5)}, ${currentLatLng[1].toFixed(5)}`;}
function setManualLocation(lat,lng,showToast=false){currentLatLng=[lat,lng]; updateLocationField(); if(manualLayer){manualLayer.clearLayers(); L.circleMarker(currentLatLng,{radius:10,color:'#168cff',fillColor:'#168cff',fillOpacity:.35,weight:3}).addTo(manualLayer); L.marker(currentLatLng,{icon:L.divIcon({className:'',html:'<div class=\"dropPin\">＋</div>',iconSize:[30,30],iconAnchor:[15,15]})}).addTo(manualLayer);} if(showToast) flashMessage('Catch location set. Tap Log Catch to save fish here.');}
function numVal(id){const el=document.getElementById(id); const raw=(el?.value||el?.placeholder||'').trim(); return raw===''?'':Number(raw);}

function isBassSpecies(species){return /bass/i.test(species||'');}
function autoKeeperFor(species,length){return isBassSpecies(species) && (+length||0)>=15;}
function keeperFromForm(species,length){const choice=document.getElementById('keeper')?.value||'auto'; if(choice==='yes')return true; if(choice==='no')return false; return autoKeeperFor(species,length);}
function isKeeperCatch(c){return typeof c.keeper==='boolean'?c.keeper:autoKeeperFor(c.species,c.length);}
function keeperBadge(c){return isKeeperCatch(c)?'<span class="keeperBadge keeperYes">Keeper</span>':'<span class="keeperBadge keeperNo">Short</span>';}
function currentWeatherSnapshot(){if(!currentWeather)return null; return {temp:currentWeather.temp,humidity:currentWeather.humidity,wind:currentWeather.wind,pressure:currentWeather.pressure,precip:currentWeather.precip,code:currentWeather.code,text:currentWeather.text,icon:currentWeather.icon,label:currentWeather.label,time:currentWeather.time};}
function weatherSummary(w){return w?`${w.temp}°F ${w.text}, wind ${w.wind} mph`:'Not saved';}
function commonField(arr,field,fallback='Log more catches'){const m={}; arr.forEach(c=>{const v=(c[field]||'').trim?.()||c[field]; if(v&&v!=='Not logged')m[v]=(m[v]||0)+1;}); return Object.entries(m).sort((a,b)=>b[1]-a[1])[0]?.[0]||fallback;}
function saveCatch(){const species=val('species')||'Largemouth Bass'; const length=numVal('length'); const c={id:crypto.randomUUID(),species,length,weight:numVal('weight'),lure:getSelectedLure()||selectedLure||'No lure selected',depth:numVal('depth'),waterTemp:numVal('waterTemp'),keeper:keeperFromForm(species,length),keeperRule:document.getElementById('keeper')?.value||'auto',areaType:val('areaType')||'Not logged',coverType:val('coverType')||'Not logged',weather:currentWeatherSnapshot(),lake:selectedLakeName,lat:currentLatLng[0],lng:currentLatLng[1],notes:val('notes'),photo:currentPhotoData||'',date:new Date().toISOString()}; catches.push(c); save(); resetPhotoInput(); if(manualLayer)manualLayer.clearLayers(); renderMap(); renderPattern(); switchView('mapView'); flashMessage('Catch saved with weather and pattern details.');}
function val(id){return document.getElementById(id)?.value||''}
function historyThumbs(c){const speciesThumb=speciesImage(c), photo=catchPhoto(c), speciesLabel=speciesThumbLabel(c.species); if(!speciesThumb&&!photo)return '<div class="pinMini">🐟</div>'; return `<div class="historyThumbPair">${speciesThumb?`<img class="thumbMini" src="${speciesThumb}" alt="${escapeHtml(speciesLabel)}">`:''}${photo?`<img class="thumbMini" src="${photo}" alt="Catch photo">`:''}</div>`;}
function renderHistory(){const list=document.getElementById('historyList'); const visibleCatches=activeCatches(); if(!visibleCatches.length){list.innerHTML=`<div class="catchRow"><p>No catches yet for ${escapeHtml(selectedLakeName)}.</p></div>`;return;} list.innerHTML=visibleCatches.slice().reverse().map(c=>`<div class="catchRow" data-id="${c.id}">${editMode?`<input type="checkbox" class="catchCheck" value="${c.id}">`:''}${historyThumbs(c)}<div><h3>${escapeHtml(c.species)} — ${fmt(c.length)} in ${keeperBadge(c)}</h3><p>${new Date(c.date).toLocaleString()} · ${escapeHtml(c.lure||'No lure')}</p><p>${escapeHtml(c.areaType||'Area not logged')} · ${escapeHtml(c.coverType||'Cover not logged')}</p></div><button class="rowOpen" data-id="${c.id}">›</button></div>`).join(''); document.querySelectorAll('.rowOpen').forEach(b=>b.onclick=()=>showCatchDetail(b.dataset.id)); document.querySelectorAll('.catchRow').forEach(r=>{r.onclick=e=>{if(e.target.type==='checkbox'||e.target.className==='rowOpen')return; if(editMode){const cb=r.querySelector('.catchCheck'); if(cb)cb.checked=!cb.checked;}else showCatchDetail(r.dataset.id)}});}
function toggleEdit(){editMode=!editMode;document.getElementById('bulkBar').classList.toggle('hidden',!editMode);document.getElementById('editHistoryBtn').textContent=editMode?'Done':'Select';renderHistory();}
function deleteSelected(){const ids=[...document.querySelectorAll('.catchCheck:checked')].map(x=>x.value); if(!ids.length){alert('Select at least one catch.');return;} if(!confirm(`Delete ${ids.length} selected catch(es)?`))return; catches=catches.filter(c=>!ids.includes(c.id)); save(); renderHistory(); renderMap();}
function resetAll(){if(confirm('Delete ALL catches and pins?')){catches=[];save();renderHistory();renderMap();}}
function renderStats(){const visibleCatches=activeCatches(); const keepers=visibleCatches.filter(isKeeperCatch); document.getElementById('statsBox').innerHTML=`<h3>${escapeHtml(selectedLakeName)}</h3><p>Total catches: ${visibleCatches.length}</p><p>Keepers: ${keepers.length}</p><p>Biggest fish: ${Math.max(0,...visibleCatches.map(c=>+c.length||0))} in</p><p>Best lure: ${escapeHtml(bestLure(visibleCatches))}</p><p>Best area: ${escapeHtml(commonField(keepers.length?keepers:visibleCatches,'areaType','—'))}</p><p>Best cover: ${escapeHtml(commonField(keepers.length?keepers:visibleCatches,'coverType','—'))}</p>`}
function renderLures(){document.getElementById('lureList').innerHTML=lures.map(l=>`<div class="catchRow"><div class="pinMini">🪱</div><div><h3>${escapeHtml(l)}</h3><p>Saved lure</p></div></div>`).join('')}
function addLure(){const l=prompt('Enter new lure name/color'); if(l){lures.push(l);selectedLure=l;save();renderLures();}}

function initLureSelectors(){
  const type=document.getElementById('lureType'), exact=document.getElementById('lureExact'), color=document.getElementById('lureColor');
  if(!type||!exact||!color)return;
  type.innerHTML=Object.keys(LURE_DB).map(t=>`<option>${escapeHtml(t)}</option>`).join('');
  type.value='Soft Plastics';
  type.onchange=()=>populateExact(); exact.onchange=()=>populateColors(); color.onchange=()=>{selectedLure=getSelectedLure();};
  populateExact();
}
function populateExact(){
  const type=document.getElementById('lureType'), exact=document.getElementById('lureExact');
  const items=LURE_DB[type.value]||LURE_DB.Other;
  exact.innerHTML=items.map(x=>`<option>${escapeHtml(x.name)}</option>`).join('');
  exact.value=items[0].name;
  populateColors();
}
function populateColors(){
  const type=document.getElementById('lureType'), exact=document.getElementById('lureExact'), color=document.getElementById('lureColor');
  const item=(LURE_DB[type.value]||[]).find(x=>x.name===exact.value) || LURE_DB.Other[0];
  color.innerHTML=item.colors.map(c=>`<option>${escapeHtml(c)}</option>`).join('');
  color.value=item.colors[0];
  selectedLure=getSelectedLure();
}
function getSelectedLure(){
  const type=document.getElementById('lureType')?.value||'';
  const exact=document.getElementById('lureExact')?.value||'';
  const color=document.getElementById('lureColor')?.value||'';
  if(!exact)return selectedLure;
  return color && color!=='Custom / Other' ? `${exact} - ${color}` : exact;
}
function addCustomLureFromForm(){
  const type=prompt('Lure category/type?', document.getElementById('lureType')?.value || 'Other') || 'Other';
  const name=prompt('Exact lure name?', 'Custom Lure'); if(!name)return;
  const color=prompt('Color?', 'Custom / Other') || 'Custom / Other';
  if(!LURE_DB[type]) LURE_DB[type]=[];
  LURE_DB[type].push({name,colors:[color,'Custom / Other']});
  const formatted=`${type} | ${name} - ${color}`;
  if(!lures.includes(formatted)) lures.push(formatted);
  save(); initLureSelectors();
  document.getElementById('lureType').value=type; populateExact();
  document.getElementById('lureExact').value=name; populateColors();
  document.getElementById('lureColor').value=color; selectedLure=getSelectedLure();
}


function handlePhotoFile(file){
  if(!file)return;
  if(!file.type.startsWith('image/')){alert('Please choose an image file.');return;}
  const reader=new FileReader();
  reader.onload=()=>resizeImage(reader.result,900,0.82).then(data=>{
    currentPhotoData=data;
    const img=document.getElementById('photoPreview');
    img.src=data; img.classList.remove('hidden');
    document.getElementById('clearPhoto').classList.remove('hidden');
  });
  reader.readAsDataURL(file);
}
function resizeImage(dataUrl,maxSize=900,quality=.82){return new Promise(resolve=>{const img=new Image(); img.onload=()=>{let {width,height}=img; const scale=Math.min(1,maxSize/Math.max(width,height)); width=Math.round(width*scale); height=Math.round(height*scale); const canvas=document.createElement('canvas'); canvas.width=width; canvas.height=height; const ctx=canvas.getContext('2d'); ctx.drawImage(img,0,0,width,height); resolve(canvas.toDataURL('image/jpeg',quality));}; img.src=dataUrl;});}
function resetPhotoInput(){currentPhotoData=''; const input=document.getElementById('fishPhoto'); if(input)input.value=''; const img=document.getElementById('photoPreview'); if(img){img.src=''; img.classList.add('hidden');} const btn=document.getElementById('clearPhoto'); if(btn)btn.classList.add('hidden');}
function goHotspot(){
  const visibleCatches=activeCatches();
  if(!visibleCatches.length){map.setView(LAKE_CENTER,selectedLake().zoom||14); flashMessage(`No catches logged for ${selectedLakeName} yet.`); return;}
  const recentCut=Date.now()-1000*60*60*24*90;
  const scored=clusterCatches(visibleCatches,110).map(g=>{const recent=g.items.filter(c=>new Date(c.date).getTime()>recentCut).length; const big=g.items.filter(c=>/bass/i.test(c.species||'') && (+c.length>=15)).length; return {g,score:g.items.length+(recent*1.5)+(big*2)};}).sort((a,b)=>b.score-a.score)[0];
  map.flyTo(scored.g.center,17,{animate:true,duration:.8});
  flashMessage(`Jumped to hottest ${selectedLake().short} area: ${scored.g.items.length} catch(es).`);
  setTimeout(renderMap,900);
}

function weatherCodeText(code){
  const map={0:['☀️','Clear'],1:['🌤️','Mostly clear'],2:['⛅','Partly cloudy'],3:['☁️','Cloudy'],45:['🌫️','Fog'],48:['🌫️','Fog'],51:['🌦️','Light drizzle'],53:['🌦️','Drizzle'],55:['🌧️','Heavy drizzle'],61:['🌦️','Light rain'],63:['🌧️','Rain'],65:['🌧️','Heavy rain'],71:['🌨️','Light snow'],73:['🌨️','Snow'],75:['❄️','Heavy snow'],80:['🌦️','Rain showers'],81:['🌧️','Showers'],82:['⛈️','Heavy showers'],95:['⛈️','Thunderstorm'],96:['⛈️','Storms'],99:['⛈️','Storms']};
  return map[Number(code)]||['🌤️','Weather'];
}
function setWeatherCardLoading(msg='Updating weather…'){
  const card=document.getElementById('weatherCard');
  if(card)card.classList.add('loading');
  const main=document.getElementById('weatherMain');
  const sub=document.getElementById('weatherSub');
  if(main)main.textContent=msg;
  if(sub)sub.textContent=`${weatherLabel} · live weather`;
}
async function fetchWeather(lat=LAKE_CENTER[0],lng=LAKE_CENTER[1],label='Taylorsville Lake'){
  weatherCoords=[lat,lng]; weatherLabel=label;
  setWeatherCardLoading();
  try{
    const params=new URLSearchParams({
      latitude:String(lat), longitude:String(lng),
      current:'temperature_2m,relative_humidity_2m,precipitation,weather_code,wind_speed_10m,pressure_msl,is_day',
      temperature_unit:'fahrenheit', wind_speed_unit:'mph', precipitation_unit:'inch', timezone:'auto'
    });
    const res=await fetch(`https://api.open-meteo.com/v1/forecast?${params.toString()}`);
    if(!res.ok)throw new Error('Weather request failed');
    const data=await res.json();
    const w=data.current||{};
    const [icon,text]=weatherCodeText(w.weather_code);
    currentWeather={temp:Math.round(w.temperature_2m),humidity:Math.round(w.relative_humidity_2m||0),wind:Math.round(w.wind_speed_10m||0),pressure:Math.round(w.pressure_msl||0),precip:w.precipitation||0,code:w.weather_code,text,icon,label,lat,lng,time:w.time};
    updateWeatherCard();
    renderPattern();
  }catch(err){
    const icon=document.getElementById('weatherIcon'),main=document.getElementById('weatherMain'),sub=document.getElementById('weatherSub'),card=document.getElementById('weatherCard');
    if(icon)icon.textContent='🌤️';
    if(main)main.textContent='Weather unavailable';
    if(sub)sub.textContent='Tap to retry GPS weather';
    if(card)card.classList.remove('loading');
  }
}
function updateWeatherCard(){
  const w=currentWeather; if(!w)return;
  const icon=document.getElementById('weatherIcon'),main=document.getElementById('weatherMain'),sub=document.getElementById('weatherSub'),card=document.getElementById('weatherCard');
  if(icon)icon.textContent=w.icon;
  if(main)main.textContent=`${w.temp}°F ${w.text}`;
  if(sub)sub.textContent=`${w.label} · wind ${w.wind} mph · humidity ${w.humidity}%`;
  if(card)card.classList.remove('loading');
}
function refreshWeatherWithGps(){
  if(!navigator.geolocation){fetchWeather(...LAKE_CENTER,'Taylorsville Lake');return;}
  navigator.geolocation.getCurrentPosition(p=>fetchWeather(p.coords.latitude,p.coords.longitude,'GPS location'),()=>fetchWeather(...LAKE_CENTER,'Taylorsville Lake'),{enableHighAccuracy:true,timeout:9000,maximumAge:60000});
}

function patternCandidates(){
  const visibleCatches=activeCatches();
  if(!visibleCatches.length)return [];
  const now=new Date();
  const month=now.getMonth();
  const temp=currentWeather?.temp;
  const keepers=visibleCatches.filter(isKeeperCatch);
  const pool=keepers.length>=3?keepers:visibleCatches;
  return pool.map(c=>{
    const d=new Date(c.date||Date.now());
    let score=1;
    const len=+c.length||0, wt=+c.weight||0, depth=+c.depth||0, water=+c.waterTemp||0;
    score+=Math.min(5,len/4)+Math.min(3,wt);
    if(isKeeperCatch(c))score+=4;
    if(d.getMonth()===month)score+=2.5;
    if(water && temp){
      const diff=Math.abs(water-temp);
      if(diff<=5)score+=2; else if(diff<=10)score+=1;
    }
    if(c.areaType)score+=1;
    if(c.coverType)score+=1;
    if(depth>0)score+=.5;
    return {...c,_score:score};
  }).sort((a,b)=>b._score-a._score);
}
function average(nums){const good=nums.filter(n=>Number.isFinite(n)&&n>0); return good.length?good.reduce((a,b)=>a+b,0)/good.length:0;}
function lureFrom(arr){const m={}; arr.forEach(c=>{const l=c.lure||'No lure logged'; m[l]=(m[l]||0)+1+(isKeeperCatch(c)?1.5:0);}); return Object.entries(m).sort((a,b)=>b[1]-a[1])[0]?.[0]||'Log more catches';}
function renderPattern(){
  const box=document.getElementById('patternBox'); if(!box)return;
  const visibleCatches=activeCatches();
  if(!visibleCatches.length){
    lastPatternCluster=null;
    box.innerHTML=`<div class="patternHero"><h3>Pattern needs catches</h3><p>Log catches for this lake with lure, depth, water temp, keeper status, area type, cover type, and location. After several catches on the selected lake, this screen will suggest bait and areas based on what has worked.</p></div><p class="patternNote">Live weather is ${currentWeather?`active: ${currentWeather.temp}°F ${currentWeather.text}.`:`loading from ${selectedLakeName}.`}</p>`;
    return;
  }
  const keepers=visibleCatches.filter(isKeeperCatch);
  const candidates=patternCandidates();
  const top=candidates.slice(0,Math.min(10,candidates.length));
  const best=candidates[0];
  const clusters=clusterCatches(top,130).sort((a,b)=>b.items.length-a.items.length || average(b.items.map(c=>+c.length||0))-average(a.items.map(c=>+c.length||0)));
  lastPatternCluster=clusters[0]||null;
  const suggestedLure=lureFrom(top);
  const suggestedArea=commonField(top,'areaType','Log area type');
  const suggestedCover=commonField(top,'coverType','Log cover type');
  const avgDepth=average(top.map(c=>+c.depth||0));
  const depthText=avgDepth?`${Math.max(1,Math.round(avgDepth-2))}–${Math.round(avgDepth+2)} ft`:'Log depth';
  const waterAvg=average(top.map(c=>+c.waterTemp||0));
  const areaText=lastPatternCluster?`${lastPatternCluster.items.length} matching catch(es) near your best cluster`:'No map cluster yet';
  const weatherText=currentWeather?`${currentWeather.temp}°F ${currentWeather.text}, wind ${currentWeather.wind} mph`:'Weather loading';
  const confidence=visibleCatches.length>=20?'High':visibleCatches.length>=8?'Medium':'Low';
  const keeperNote=keepers.length>=3?`Prioritizing ${keepers.length} keeper catch(es).`:`Only ${keepers.length} keeper catch(es) logged, so short fish are still included.`;
  box.innerHTML=`
    <div class="patternHero"><h3>Today’s Game Plan</h3><p>${escapeHtml(confidence)} confidence based on ${visibleCatches.length} logged catch(es). ${escapeHtml(keeperNote)}</p></div>
    <div class="patternGrid">
      <div class="patternTile"><b>Suggested bait</b><small>${escapeHtml(suggestedLure)}</small></div>
      <div class="patternTile"><b>Target depth</b><small>${escapeHtml(depthText)}${waterAvg?` · water ${waterAvg.toFixed(0)}°F pattern`:''}</small></div>
      <div class="patternTile"><b>Area type</b><small>${escapeHtml(suggestedArea)}</small></div>
      <div class="patternTile"><b>Cover type</b><small>${escapeHtml(suggestedCover)}</small></div>
      <div class="patternTile"><b>Map area</b><small>${escapeHtml(areaText)}</small></div>
      <div class="patternTile"><b>Weather angle</b><small>${escapeHtml(weatherText)}</small></div>
      <div class="patternTile patternWide"><b>Best matching catch</b><small>${keeperBadge(best)} ${escapeHtml(best.species)} · ${fmt(best.length)} in · ${escapeHtml(best.lure||'No lure')} · ${fmt(best.depth)} ft · ${escapeHtml(best.areaType||'Area not logged')} / ${escapeHtml(best.coverType||'Cover not logged')}</small></div>
    </div>
    <button type="button" class="patternAction" id="showPatternAreaBtn">Show suggested area on map</button>
    <p class="patternNote">Pattern uses logged lure, depth, water temp, keeper status, area type, cover type, season, lake, catch size, location, and the current live weather. Trophy pin still marks the lake’s largest catch.</p>`;
  const btn=document.getElementById('showPatternAreaBtn'); if(btn)btn.onclick=showPatternAreaOnMap;
}
function showPatternAreaOnMap(){
  if(!lastPatternCluster){flashMessage('Log more catches to build a suggested area.');return;}
  switchView('mapView');
  setTimeout(()=>{map.flyTo(lastPatternCluster.center,17,{animate:true,duration:.8}); flashMessage(`Suggested area: ${lastPatternCluster.items.length} matching catch(es).`); renderMap();},180);
}

function openPhotoModal(src){const modal=document.getElementById('photoModal'), img=document.getElementById('photoModalImg'); if(!modal||!img||!src)return; img.src=src; modal.classList.remove('hidden');}
function closePhotoModal(){const modal=document.getElementById('photoModal'), img=document.getElementById('photoModalImg'); if(img)img.src=''; if(modal)modal.classList.add('hidden');}

function fmt(v){return (v===0||v)?v:'—'}
function flashMessage(msg){let el=document.getElementById('toast'); if(!el){el=document.createElement('div'); el.id='toast'; document.body.appendChild(el);} el.textContent=msg; el.className='toast show'; setTimeout(()=>el.className='toast',2200);}
function escapeHtml(s){return String(s??'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]))}


function setupKeeperAutoHint(){
  const len=document.getElementById('length'), species=document.getElementById('species'), keeper=document.getElementById('keeper');
  const update=()=>{if(!keeper||keeper.value!=='auto')return; const isKeeper=autoKeeperFor(species?.value||'',Number(len?.value||0)); keeper.title=isKeeper?'Auto: keeper':'Auto: short fish';};
  len?.addEventListener('input',update); species?.addEventListener('change',update); keeper?.addEventListener('change',update); update();
}

